const fs = require('fs');
const _ = require('lodash');
const yargs = require('yargs');

class Common{

    constructor(){
    }

    /**
     * cli 가 전달한 --env={} 아규먼트값을 반환한다.
     */
    getEnvArgs(){

        const argv = yargs.argv;

        const ptn = /\s*([\w.]+)\s*:\s*([\w.]+)\s*/g;

        let env = argv.env;

        env = env.replace(/^\'/, '').replace(/\'$/, '');
        env = env.replace(ptn, '"$1":"$2"');

        env = JSON.parse(env);

        env.verbose = this.toBoolean(env.verbose);
        env.liveupdate = this.toBoolean(env.liveupdate);

        return env;
    }
    toBoolean(v = ''){

        let ret = false;

        if (_.trim(v) === 'true'){
            ret = true;
        }

        return ret;
    }
}

module.exports = Common;
